  1	import { type FC, useEffect, useMemo } from 'react';
  2	import { Form, FormProvider, useForm } from 'react-hook-form';
  3	import { StorageMapFieldId } from 'src/storageMaps/constants';
  4	
  5	import type { V1beta1Provider, V1beta1StorageMap } from '@kubev2v/types';
  6	import { Button, ButtonVariant, Flex, FlexItem, Split } from '@patternfly/react-core';
  7	import { useForkliftTranslation } from '@utils/i18n';
  8	
  9	import type { StorageMappingValue, TargetStorage } from '../../types';
 10	import type { UpdateMappingsFormData } from '../constants';
 11	import { transformStorageMapToFormValues } from '../utils';
 12	
 13	import UpdateStorageMapFieldTable from './UpdateStorageMapFieldTable';
 14	
 15	import './UpdateStorageMapForm.style.scss';
 16	
 17	type UpdateStorageMapFormProps = {
 18	  storageMap: V1beta1StorageMap;
 19	  targetStorages: TargetStorage[];
 20	  usedSourceStorages: StorageMappingValue[];
 21	  otherSourceStorages: StorageMappingValue[];
 22	  isLoading: boolean;
 23	  loadError: Error | null;
 24	  isVsphere: boolean;
 25	  onUpdate: (values: UpdateMappingsFormData) => Promise<void>;
 26	  onCancel: () => void;
 27	  sourceProvider: V1beta1Provider | undefined;
 28	};
 29	
 30	const UpdateStorageMapForm: FC<UpdateStorageMapFormProps> = ({
 31	  isLoading,
 32	  isVsphere,
 33	  loadError,
 34	  onCancel,
 35	  onUpdate,
 36	  otherSourceStorages,
 37	  sourceProvider,
 38	  storageMap,
 39	  targetStorages,
 40	  usedSourceStorages,
 41	}) => {
 42	  const { t } = useForkliftTranslation();
 43	
 44	  const initialFormValues = useMemo(
 45	    () => transformStorageMapToFormValues(storageMap),
 46	    [storageMap],
 47	  );
 48	
 49	  const form = useForm<UpdateMappingsFormData>({
 50	    defaultValues: initialFormValues,
 51	    mode: 'onChange',
 52	  });
 53	
 54	  const {
 55	    formState: { isDirty, isSubmitting, isValid },
 56	    handleSubmit,
 57	    reset,
 58	    watch,
 59	  } = form;
 60	  const formValues = watch();
 61	
 62	  // Reset form when storageMap changes
 63	  useEffect(() => {
 64	    reset(initialFormValues);
 65	  }, [initialFormValues, reset]);
 66	
 67	  const handleCancel = () => {
 68	    reset(initialFormValues);
 69	    onCancel();
 70	  };
 71	
 72	  const handleUpdateMappings = handleSubmit(async () => {
 73	    const filteredStorageMap = formValues.storageMap?.filter((mapping) => {
 74	      const hasSource = Boolean(mapping[StorageMapFieldId.SourceStorage]?.name);
 75	      const hasTarget = Boolean(mapping[StorageMapFieldId.TargetStorage]?.name);
 76	
 77	      return hasSource || hasTarget;
 78	    });
 79	
 80	    await onUpdate({
 81	      storageMap: filteredStorageMap,
 82	    });
 83	  });
 84	
 85	  return (
 86	    <FormProvider {...form}>
 87	      <Flex
 88	        direction={{ default: 'column' }}
 89	        spaceItems={{ default: 'spaceItemsXl' }}
 90	        className="update-storage-map-form"
 91	      >
 92	        <FlexItem>
 93	          <Split hasGutter>
 94	            <Button
 95	              onClick={handleUpdateMappings}
 96	              isDisabled={!isValid || isSubmitting || !isDirty}
 97	              isLoading={isSubmitting}
 98	            >
 99	              {t('Update mappings')}
100	            </Button>
101	
102	            <Button
103	              variant={ButtonVariant.secondary}
104	              onClick={handleCancel}
105	              isDisabled={!isDirty || isSubmitting}
106	            >
107	              {t('Cancel')}
108	            </Button>
109	          </Split>
110	        </FlexItem>
111	
112	        <Form>
113	          <UpdateStorageMapFieldTable
114	            targetStorages={targetStorages}
115	            usedSourceStorages={usedSourceStorages}
116	            otherSourceStorages={otherSourceStorages}
117	            isLoading={isLoading}
118	            loadError={loadError}
119	            isVsphere={isVsphere}
120	            sourceProvider={sourceProvider}
121	          />
122	        </Form>
123	      </Flex>
124	    </FormProvider>
125	  );
126	};
127	
128	export default UpdateStorageMapForm;

